package org.apache.commons.csv;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.Constants;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

class CSVPrinterPrintTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrint_nullValue_nullStringNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        when(format.getNullString()).thenReturn(null);

        // Use reflection to invoke private print method and verify its arguments
        CSVPrinter spyPrinter = Mockito.spy(printer);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        // Call public print method on spy
        spyPrinter.print(null);

        // Verify private print was called with expected args by intercepting via reflection
        // We cannot verify private method call directly, so we use a custom Answer to capture arguments

        // Instead of verify(spy).print(...) which fails due to private access,
        // we intercept the private method call via a Mockito spy with doAnswer

        // Create a holder for the arguments
        final Object[] capturedArgs = new Object[4];

        // Setup spy to intercept private print
        doAnswer(invocation -> {
            capturedArgs[0] = invocation.getArgument(0);
            capturedArgs[1] = invocation.getArgument(1);
            capturedArgs[2] = invocation.getArgument(2);
            capturedArgs[3] = invocation.getArgument(3);
            return null;
        }).when(spyPrinter, "print", any(), any(), anyInt(), anyInt());

        // Call public print again to trigger interception
        spyPrinter.print(null);

        // Verify captured arguments
        assertNull(capturedArgs[0]);
        assertEquals(Constants.EMPTY, capturedArgs[1]);
        assertEquals(0, capturedArgs[2]);
        assertEquals(Constants.EMPTY.length(), capturedArgs[3]);
    }

    @Test
    void testPrint_nullValue_nullStringNonNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        final String nullString = "NULLSTR";
        when(format.getNullString()).thenReturn(nullString);

        CSVPrinter spyPrinter = Mockito.spy(printer);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        final Object[] capturedArgs = new Object[4];

        doAnswer(invocation -> {
            capturedArgs[0] = invocation.getArgument(0);
            capturedArgs[1] = invocation.getArgument(1);
            capturedArgs[2] = invocation.getArgument(2);
            capturedArgs[3] = invocation.getArgument(3);
            return null;
        }).when(spyPrinter, "print", any(), any(), anyInt(), anyInt());

        spyPrinter.print(null);

        assertNull(capturedArgs[0]);
        assertEquals(nullString, capturedArgs[1]);
        assertEquals(0, capturedArgs[2]);
        assertEquals(nullString.length(), capturedArgs[3]);
    }

    @Test
    void testPrint_nonNullValue() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        String value = "value";

        CSVPrinter spyPrinter = Mockito.spy(printer);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        final Object[] capturedArgs = new Object[4];

        doAnswer(invocation -> {
            capturedArgs[0] = invocation.getArgument(0);
            capturedArgs[1] = invocation.getArgument(1);
            capturedArgs[2] = invocation.getArgument(2);
            capturedArgs[3] = invocation.getArgument(3);
            return null;
        }).when(spyPrinter, "print", any(), any(), anyInt(), anyInt());

        spyPrinter.print(value);

        assertEquals(value, capturedArgs[0]);
        assertEquals(value, capturedArgs[1]);
        assertEquals(0, capturedArgs[2]);
        assertEquals(value.length(), capturedArgs[3]);
    }

    @Test
    void testPrint_privatePrint_invocation() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Test coverage for private print method called by public print

        String value = "abc";
        Method privatePrint = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        privatePrint.setAccessible(true);

        // Call private print directly
        privatePrint.invoke(printer, value, value, 0, value.length());

        // No exception means success; coverage for private print
    }
}
